-- One-time seed for custom-embeds (SQLite/Turso). Do not re-run on a populated DB.
CREATE TABLE IF NOT EXISTS module_custom_embeds (
  key   TEXT PRIMARY KEY,
  value TEXT NOT NULL
);

INSERT INTO module_custom_embeds(key,value) VALUES('editorConfig','{"title":"Custom Embeds","description":"Publish static info embeds to Discord channels. Configure each panel, save, then publish.","fields":[{"key":"panels","label":"Embed panels","type":"object-list","store":"config","itemLabel":"Embed panel","publishable":true,"collapsible":true,"defaultItem":{"id":"","published":false,"channelId":"","showTimestamp":false,"panelTitle":"","panelDescription":"","authorName":"","authorIconUrl":"","footer":""},"itemFields":[{"key":"channelId","label":"Channel","type":"channel","store":"config","help":"The embed message is posted here."},{"key":"panelTitle","label":"Embed title","type":"text","store":"texts"},{"key":"panelDescription","label":"Embed description","type":"textarea","store":"texts","help":"Required. Main body of the embed."},{"key":"authorName","label":"Author name","type":"text","store":"texts","help":"Optional. Shown above the embed title."},{"key":"authorIconUrl","label":"Author icon URL","type":"text","store":"texts","help":"Optional. Requires author name. Must be a valid http or https URL."},{"key":"footer","label":"Footer","type":"text","store":"texts","help":"Optional. Small text at the bottom of the embed."},{"key":"showTimestamp","label":"Show timestamp","type":"boolean","store":"config","help":"When enabled, the embed shows the publish time. Updates on re-publish."}]}]}') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_custom_embeds(key,value) VALUES('enabled','true') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_custom_embeds(key,value) VALUES('panels','[]') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
